Rule.Source:
  import sailpoint.object.Custom;
  import sailpoint.tools.Util;
  import org.json.JSONArray;
  import org.json.JSONObject; 
  import sailpoint.object.Identity;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  private static Log logger = LogFactory.getLog("sailpoint.services.asc.Gsuite"); 

  if(value != null){
    String GSUITE_CUSTOM_OBJECT_NAME="Ascension-Custom-Gsuite";
    Custom gsuiteCustomObject = context.getObject(Custom.class,GSUITE_CUSTOM_OBJECT_NAME);
    if(gsuiteCustomObject != null){
      List restrictedAlias = gsuiteCustomObject.getList("gsuite_excluded_aliasses");
      String restrictedAliasString = "";
      if(restrictedAlias!= null){
        restrictedAliasString = sailpoint.tools.Util.listToCsv(restrictedAlias).toLowerCase();
      }

      logger.debug("Starting rule - restrictedAliasString= "+restrictedAliasString);
      List currentValueList = new ArrayList();
      List targetValueList = new ArrayList();
      if(value instanceof List){
        currentValueList.addAll(value);
      } else if(value instanceof String){
        currentValueList.add(value);
      }

      if(currentValueList.size()>0){
        for(String eachAlias : currentValueList){
          String aliasLowerCase = eachAlias.toLowerCase().split("@")[1];
          logger.debug(" processing aliasLowerCase :after @ sign ---- ["+aliasLowerCase+"]");
          if(eachAlias.startsWith("smtp:") && !restrictedAliasString.contains(aliasLowerCase)){
            String localAlias=eachAlias.split(":")[1];
            logger.debug(" processing localAlias ... ["+localAlias+"]");
            targetValueList.add(localAlias); //Takes only lowercases and ignore capital SMTP
          }
        }
      }
      return targetValueList;
    }
  }

return null;
